#include <stdio.h>
#define MOD 1000000007
long long dp[100001];
int main() {
    int T;
    scanf("%d", &T);
    dp[3] = 1;
    for (int i = 4; i <= 100000; i++) {
        dp[i] = (dp[i-1] * (i-2)) % MOD;
    }
    while (T--) {
        int N;
        scanf("%d", &N);
        printf("%lld\n", dp[N]);
    }
    return 0;
}

