import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        long[] dp = new long[100001];
        dp[3] = 1;
        for (int i = 4; i <= 100000; i++) {
            dp[i] = (dp[i-1] * (i-2)) % 1000000007;
        }
        while (T-- > 0) {
            int N = sc.nextInt();
            System.out.println(dp[N]);
        }
    }
}

